'use client';

import { useEffect, useMemo, useState } from 'react';
import {
  activateAIProvider,
  createAIProvider,
  deleteAIProvider,
  listAIProviders,
  updateAIProvider,
  type AIProviderKind,
  type AIProviderRegistryItem,
  type UpsertAIProviderPayload,
} from '@/lib/api';

interface ModelInfo {
  id: string;
  owned_by?: string;
}

interface ProviderFormState {
  id: string;
  name: string;
  provider: AIProviderKind;
  base_url: string;
  api_key: string;
  model: string;
  is_enabled: boolean;
}

const emptyProviderForm: ProviderFormState = {
  id: '',
  name: '',
  provider: 'openai-compatible',
  base_url: '',
  api_key: '',
  model: '',
  is_enabled: true,
};

function providerLabel(provider: AIProviderKind): string {
  return provider === 'openai' ? 'OpenAI' : 'OpenAI-compatible';
}

export default function AdminSettingsPage() {
  const [appName, setAppName] = useState('MathAI');
  const [supportEmail, setSupportEmail] = useState('support@mathai.vn');
  const [defaultModel, setDefaultModel] = useState('gpt-4o-mini');
  const [providerForm, setProviderForm] = useState<ProviderFormState>(emptyProviderForm);
  const [providers, setProviders] = useState<AIProviderRegistryItem[]>([]);
  const [loadingProviders, setLoadingProviders] = useState(true);
  const [providerError, setProviderError] = useState('');
  const [models, setModels] = useState<ModelInfo[]>([]);
  const [selectedModel, setSelectedModel] = useState('');
  const [fetchingModels, setFetchingModels] = useState(false);
  const [fetchError, setFetchError] = useState('');
  const [saveMsg, setSaveMsg] = useState('');
  const [saveAiMsg, setSaveAiMsg] = useState('');

  const activeProvider = useMemo(
    () => providers.find((provider) => provider.is_active) ?? null,
    [providers],
  );

  useEffect(() => {
    try {
      const general = JSON.parse(localStorage.getItem('mathai-settings-general') || '{}');
      if (general.appName) setAppName(general.appName);
      if (general.supportEmail) setSupportEmail(general.supportEmail);

      const ai = JSON.parse(localStorage.getItem('mathai-settings-ai') || '{}');
      if (ai.defaultModel) setDefaultModel(ai.defaultModel);
      if (ai.selectedModel) setSelectedModel(ai.selectedModel);
    } catch {}

    void refreshProviders();
  }, []);

  async function refreshProviders() {
    setLoadingProviders(true);
    setProviderError('');
    try {
      const list = await listAIProviders();
      setProviders(list);
      const preferred = list.find((provider) => provider.is_active) ?? list[0];
      if (preferred) {
        setDefaultModel(preferred.model);
        setSelectedModel(preferred.model);
      }
    } catch (err) {
      setProviderError(err instanceof Error ? err.message : 'Kh?ng th? t?i danh s?ch AI provider');
    } finally {
      setLoadingProviders(false);
    }
  }

  function saveGeneral() {
    localStorage.setItem('mathai-settings-general', JSON.stringify({ appName, supportEmail }));
    setSaveMsg('?? l?u c?i ??t!');
    setTimeout(() => setSaveMsg(''), 2000);
  }

  function editProvider(provider: AIProviderRegistryItem) {
    setProviderForm({
      id: provider.id,
      name: provider.name,
      provider: provider.provider,
      base_url: provider.base_url,
      api_key: '',
      model: provider.model,
      is_enabled: provider.is_enabled,
    });
    setSelectedModel(provider.model);
    setModels([]);
    setFetchError('');
    setSaveAiMsg('');
  }

  async function saveAi() {
    const model = providerForm.model.trim() || selectedModel.trim();
    if (!providerForm.name.trim()) {
      setSaveAiMsg('Vui l?ng nh?p t?n provider');
      return;
    }
    if (!providerForm.base_url.trim()) {
      setSaveAiMsg('Vui l?ng nh?p endpoint provider');
      return;
    }
    if (!model) {
      setSaveAiMsg('Vui l?ng nh?p model');
      return;
    }
    if (!providerForm.id && !providerForm.api_key.trim()) {
      setSaveAiMsg('API key l? b?t bu?c khi t?o provider m?i');
      return;
    }

    const payload: UpsertAIProviderPayload = {
      name: providerForm.name.trim(),
      provider: providerForm.provider,
      base_url: providerForm.base_url.trim(),
      model,
      is_enabled: providerForm.is_enabled,
    };
    if (providerForm.api_key.trim()) {
      payload.api_key = providerForm.api_key.trim();
    }

    try {
      const saved = providerForm.id
        ? await updateAIProvider(providerForm.id, payload)
        : await createAIProvider(payload);
      localStorage.setItem('mathai-settings-ai', JSON.stringify({
        defaultModel: saved.model,
        selectedModel: saved.model,
      }));
      setDefaultModel(saved.model);
      setSelectedModel(saved.model);
      setProviderForm(emptyProviderForm);
      setSaveAiMsg(providerForm.id ? '?? c?p nh?t AI provider!' : '?? t?o AI provider!');
      await refreshProviders();
      setTimeout(() => setSaveAiMsg(''), 2500);
    } catch (err) {
      setSaveAiMsg(err instanceof Error ? err.message : 'Kh?ng th? l?u AI provider');
    }
  }

  async function activateProvider(providerId: string) {
    setProviderError('');
    try {
      const provider = await activateAIProvider(providerId);
      setDefaultModel(provider.model);
      setSelectedModel(provider.model);
      await refreshProviders();
    } catch (err) {
      setProviderError(err instanceof Error ? err.message : 'Kh?ng th? k?ch ho?t provider');
    }
  }

  async function removeProvider(providerId: string) {
    if (!window.confirm('X?a AI provider n?y? API key ?? l?u s? b? x?a kh?i c?u h?nh.')) {
      return;
    }
    setProviderError('');
    try {
      await deleteAIProvider(providerId);
      if (providerForm.id === providerId) setProviderForm(emptyProviderForm);
      await refreshProviders();
    } catch (err) {
      setProviderError(err instanceof Error ? err.message : 'Kh?ng th? x?a provider');
    }
  }

  async function fetchModels() {
    if (!providerForm.base_url.trim()) {
      setFetchError('Vui l?ng nh?p endpoint tr??c');
      return;
    }

    setFetchingModels(true);
    setFetchError('');
    setModels([]);

    try {
      const base = providerForm.base_url.trim().replace(/\/+$/, '');
      const res = await fetch('/api/ai/models', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ endpoint: base, apiKey: providerForm.api_key.trim() }),
      });

      const json = await res.json();
      if (!res.ok) {
        throw new Error(json.error || `HTTP ${res.status}`);
      }
      const list: ModelInfo[] = (json.data ?? json).map((m: { id: string; owned_by?: string }) => ({
        id: m.id,
        owned_by: m.owned_by,
      }));

      setModels(list);
      if (list.length > 0) {
        setSelectedModel(list[0].id);
        setProviderForm((current) => ({ ...current, model: list[0].id }));
      }
    } catch (err) {
      setFetchError(err instanceof Error ? err.message : 'Kh?ng th? k?t n?i ??n endpoint');
    } finally {
      setFetchingModels(false);
    }
  }

  return (
    <div className="max-w-4xl space-y-6">
      <h1 className="text-2xl font-bold text-gray-900">C?i ??t h? th?ng ??</h1>

      <div className="space-y-5 rounded-2xl bg-white p-6 shadow-sm ring-1 ring-gray-100">
        <h2 className="text-lg font-bold text-gray-900">C?u h?nh chung</h2>
        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">T?n ?ng d?ng</label>
          <input value={appName} onChange={(e) => setAppName(e.target.value)} className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20" />
        </div>
        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">Email h? tr?</label>
          <input value={supportEmail} onChange={(e) => setSupportEmail(e.target.value)} type="email" className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20" />
        </div>
        <button onClick={saveGeneral} className="rounded-xl bg-indigo-600 px-6 py-3 font-semibold text-white transition hover:bg-indigo-700">L?u c?i ??t</button>
        {saveMsg && <p className="text-sm font-medium text-green-600">{saveMsg}</p>}
      </div>

      <div className="space-y-5 rounded-2xl bg-white p-6 shadow-sm ring-1 ring-gray-100">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <h2 className="text-lg font-bold text-gray-900">AI Provider Registry</h2>
            <p className="mt-1 text-sm text-gray-500">Qu?n l? provider OpenAI ho?c OpenAI-compatible. API key ???c l?u ? backend v? ch? hi?n th? d?ng r?t g?n.</p>
          </div>
          <button onClick={refreshProviders} type="button" className="rounded-xl border border-gray-300 px-4 py-2 text-sm font-semibold text-gray-700 transition hover:bg-gray-50">
            L?m m?i
          </button>
        </div>

        {providerError && <p className="rounded-xl bg-red-50 px-4 py-3 text-sm text-red-700">{providerError}</p>}
        {activeProvider && (
          <p className="rounded-xl bg-emerald-50 px-4 py-3 text-sm text-emerald-700">
            Provider ?ang ho?t ??ng: <strong>{activeProvider.name}</strong> ? {activeProvider.model}
          </p>
        )}

        <div className="grid gap-4 md:grid-cols-2">
          <div>
            <label className="mb-2 block text-sm font-medium text-gray-700">T?n provider</label>
            <input value={providerForm.name} onChange={(e) => setProviderForm((current) => ({ ...current, name: e.target.value }))} placeholder="OpenRouter production" className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20" />
          </div>
          <div>
            <label className="mb-2 block text-sm font-medium text-gray-700">Lo?i provider</label>
            <select value={providerForm.provider} onChange={(e) => setProviderForm((current) => ({ ...current, provider: e.target.value as AIProviderKind }))} className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500">
              <option value="openai">OpenAI</option>
              <option value="openai-compatible">OpenAI-compatible</option>
            </select>
          </div>
        </div>
        <label className="inline-flex items-center gap-2 text-sm font-medium text-gray-700">
          <input type="checkbox" checked={providerForm.is_enabled} onChange={(e) => setProviderForm((current) => ({ ...current, is_enabled: e.target.checked }))} />
          Provider ?ang b?t
        </label>
        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">Default Model</label>
          <input value={defaultModel} readOnly className="w-full rounded-xl border border-gray-200 bg-gray-50 px-4 py-3 text-gray-600 outline-none" />
        </div>
        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">Custom Endpoint (OpenAI-compatible)</label>
          <input
            type="url"
            value={providerForm.base_url}
            onChange={(e) => setProviderForm((current) => ({ ...current, base_url: e.target.value }))}
            placeholder="https://api.openai.com/v1"
            className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20"
          />
          <p className="mt-1.5 text-xs text-gray-500">H? tr? API t??ng th?ch OpenAI nh? OpenRouter, Together, LM Studio, Ollama c? endpoint HTTP(S).</p>
        </div>
        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">API Key</label>
          <input
            type="password"
            value={providerForm.api_key}
            onChange={(e) => setProviderForm((current) => ({ ...current, api_key: e.target.value }))}
            placeholder={providerForm.id ? '?? tr?ng ?? gi? key hi?n t?i' : 'sk-...'}
            className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20"
          />
        </div>

        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">Model t? Endpoint</label>
          <div className="flex flex-col gap-2 sm:flex-row">
            <button
              type="button"
              onClick={fetchModels}
              disabled={fetchingModels}
              className="shrink-0 rounded-xl border border-indigo-600 px-4 py-3 text-sm font-semibold text-indigo-600 transition hover:bg-indigo-50 disabled:cursor-not-allowed disabled:opacity-50"
            >
              {fetchingModels ? '?ang t?i...' : 'L?y danh s?ch model'}
            </button>
            {models.length > 0 && (
              <select
                value={selectedModel}
                onChange={(e) => {
                  setSelectedModel(e.target.value);
                  setProviderForm((current) => ({ ...current, model: e.target.value }));
                }}
                className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500"
              >
                {models.map((model) => (
                  <option key={model.id} value={model.id}>
                    {model.id}{model.owned_by ? ` (${model.owned_by})` : ''}
                  </option>
                ))}
              </select>
            )}
          </div>
          {fetchError && <p className="mt-2 text-xs text-red-600">{fetchError}</p>}
          {models.length > 0 && <p className="mt-1.5 text-xs text-gray-500">T?m th?y {models.length} model. Ch?n model ?? s? d?ng.</p>}
        </div>

        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">Custom Model ID</label>
          <input
            type="text"
            value={providerForm.model || selectedModel}
            onChange={(e) => {
              setSelectedModel(e.target.value);
              setProviderForm((current) => ({ ...current, model: e.target.value }));
            }}
            placeholder="gpt-4o, deepseek-chat, llama-3.1-70b..."
            className="w-full rounded-xl border border-gray-300 px-4 py-3 outline-none transition focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20"
          />
        </div>
        <div className="flex flex-wrap gap-3">
          <button onClick={saveAi} className="rounded-xl bg-indigo-600 px-6 py-3 font-semibold text-white transition hover:bg-indigo-700">
            {providerForm.id ? 'C?p nh?t AI provider' : 'L?u AI provider'}
          </button>
          {providerForm.id && (
            <button type="button" onClick={() => setProviderForm(emptyProviderForm)} className="rounded-xl border border-gray-300 px-6 py-3 font-semibold text-gray-700 transition hover:bg-gray-50">
              H?y ch?nh s?a
            </button>
          )}
        </div>
        {saveAiMsg && <p className="text-sm font-medium text-green-600">{saveAiMsg}</p>}

        <div className="border-t border-gray-100 pt-5">
          <h3 className="text-sm font-bold uppercase tracking-wide text-gray-500">Provider ?? c?u h?nh</h3>
          {loadingProviders ? (
            <p className="mt-3 text-sm text-gray-500">?ang t?i provider...</p>
          ) : providers.length === 0 ? (
            <p className="mt-3 rounded-xl bg-gray-50 px-4 py-3 text-sm text-gray-600">Ch?a c? AI provider. T?o provider ??u ti?n ?? d?ng cho chat v? c?c lu?ng AI production.</p>
          ) : (
            <div className="mt-3 space-y-3">
              {providers.map((provider) => (
                <div key={provider.id} className="rounded-2xl border border-gray-200 p-4">
                  <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                    <div>
                      <div className="flex flex-wrap items-center gap-2">
                        <h4 className="font-semibold text-gray-900">{provider.name}</h4>
                        {provider.is_active && <span className="rounded-full bg-emerald-100 px-2 py-0.5 text-xs font-semibold text-emerald-700">Active</span>}
                        {!provider.is_enabled && <span className="rounded-full bg-gray-100 px-2 py-0.5 text-xs font-semibold text-gray-600">Disabled</span>}
                      </div>
                      <p className="mt-1 text-sm text-gray-600">{providerLabel(provider.provider)} ? {provider.model}</p>
                      <p className="mt-1 break-all text-xs text-gray-500">{provider.base_url}</p>
                      <p className="mt-1 text-xs text-gray-500">Key: {provider.api_key_masked ?? '?'}</p>
                    </div>
                    <div className="flex flex-wrap gap-2">
                      <button type="button" onClick={() => editProvider(provider)} className="rounded-lg border border-gray-300 px-3 py-2 text-sm font-semibold text-gray-700 hover:bg-gray-50">S?a</button>
                      <button type="button" disabled={provider.is_active || !provider.is_enabled} onClick={() => activateProvider(provider.id)} className="rounded-lg border border-emerald-600 px-3 py-2 text-sm font-semibold text-emerald-700 hover:bg-emerald-50 disabled:cursor-not-allowed disabled:opacity-50">K?ch ho?t</button>
                      <button type="button" onClick={() => removeProvider(provider.id)} className="rounded-lg border border-red-200 px-3 py-2 text-sm font-semibold text-red-600 hover:bg-red-50">X?a</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

