'use client';

import { useState, useEffect, useMemo } from 'react';
import Link from 'next/link';
import { Triangle, Ruler, TrendingUp, Circle, Hash, BarChart3, Clock, Sparkles, AlertCircle } from 'lucide-react';
import { useAgeTheme } from '@/contexts/AgeThemeContext';
import { getActiveCurriculum, getTodayRecommendation, listLessons, type AdaptiveRecommendation, type Curriculum, type LessonSummary } from '@/lib/api';

const iconPool = [Triangle, Ruler, TrendingUp, Circle, Hash, BarChart3];
const colorPool = ['bg-blue-500', 'bg-emerald-500', 'bg-purple-500', 'bg-rose-500', 'bg-amber-500', 'bg-cyan-500'];

const defaultSubjects = ['Tất cả'];

const difficultyConfig: Record<string, { bg: string; text: string; label: string }> = {
  'Dễ': { bg: 'bg-emerald-100', text: 'text-emerald-700', label: 'Cơ bản' },
  'Trung bình': { bg: 'bg-amber-100', text: 'text-amber-700', label: 'Trung bình' },
  'Khó': { bg: 'bg-red-100', text: 'text-red-700', label: 'Nâng cao' },
};

type LessonCard = {
  id: string;
  title: string;
  subject: string;
  grade: string;
  duration: string;
  difficulty: string;
  progress: number;
  status: string;
  icon: typeof Triangle;
  color: string;
  recommendationLabel?: string;
};

function mapDifficulty(_lesson: LessonSummary): string {
  return 'Trung bình';
}

function progressFromStatus(status?: string): number {
  if (status === 'completed') return 100;
  if (status === 'in_progress') return 50;
  return 0;
}

function statusLabel(status?: string): string {
  switch (status) {
    case 'completed': return 'Hoàn thành';
    case 'available': return 'Sẵn sàng';
    case 'scheduled': return 'Theo lịch';
    case 'skipped': return 'Đã bỏ qua';
    default: return 'Chưa bắt đầu';
  }
}

function lessonTopic(lesson: LessonSummary): string {
  return lesson.lesson_objective || 'Bài học cá nhân';
}

function lessonId(lesson: LessonSummary, index: number): string {
  return String(lesson._id || lesson.id || index + 1);
}

function getRecommendationLabel(recommendation: AdaptiveRecommendation | null, id: string): string | undefined {
  if (!recommendation) return undefined;
  if (recommendation.new_lesson?.lesson_id === id) return 'Gợi ý bài mới hôm nay';
  if (recommendation.review_items.some(item => item.lesson_id === id)) return 'Nên ôn tập hôm nay';
  if (recommendation.reinforce_items.some(item => item.lesson_id === id)) return 'Nên củng cố hôm nay';
  return undefined;
}

export default function LessonsPage() {
  const [filter, setFilter] = useState('Tất cả');
  const [mounted, setMounted] = useState(false);
  const [lessons, setLessons] = useState<LessonSummary[]>([]);
  const [activeCurriculum, setActiveCurriculum] = useState<Curriculum | null>(null);
  const [recommendation, setRecommendation] = useState<AdaptiveRecommendation | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const { theme, ageGroup } = useAgeTheme();

  useEffect(() => setMounted(true), []);

  useEffect(() => {
    let cancelled = false;

    async function fetchLessons() {
      try {
        setError(null);
        const [curriculumData, recommendationData] = await Promise.all([
          getActiveCurriculum(),
          getTodayRecommendation(),
        ]);
        const curriculumId = curriculumData?._id || curriculumData?.id;
        const lessonsData = await listLessons(curriculumId);

        if (!cancelled) {
          setActiveCurriculum(curriculumData);
          setRecommendation(recommendationData);
          setLessons(lessonsData);
        }
      } catch (err) {
        if (!cancelled) setError(err instanceof Error ? err.message : 'Không tải được danh sách bài học');
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    fetchLessons();
    return () => { cancelled = true; };
  }, []);

  const cards: LessonCard[] = useMemo(() => lessons.map((lesson, index) => {
    const id = lessonId(lesson, index);
    return {
      id,
      title: lesson.lesson_title || `Bài học ${index + 1}`,
      subject: lessonTopic(lesson),
      grade: statusLabel(lesson.status),
      duration: lesson.estimated_minutes ? `${lesson.estimated_minutes} phút` : 'Chưa có thời lượng',
      difficulty: mapDifficulty(lesson),
      progress: progressFromStatus(lesson.status),
      status: lesson.status || 'pending',
      icon: iconPool[index % iconPool.length],
      color: colorPool[index % colorPool.length],
      recommendationLabel: getRecommendationLabel(recommendation, id),
    };
  }), [lessons, recommendation]);

  const subjects = Array.from(new Set([...defaultSubjects, ...cards.map(l => l.subject).filter(Boolean)]));
  const filtered = filter === 'Tất cả' ? cards : cards.filter(l => l.subject === filter);

  const isElementary = ageGroup === 'elementary';
  const isHigh = ageGroup === 'high';
  const nextLesson = recommendation?.new_lesson;

  return (
    <div className={`flex flex-col ${theme.sectionGap}`}>
      <div>
        <h1 className={`${theme.fontWeight} text-2xl text-gray-900`}>
          {isElementary ? 'Bài học vui' : isHigh ? 'Bài học' : 'Bài học'}
        </h1>
        <p className={`text-gray-500 mt-1 text-xl`}>
          {isElementary
            ? 'Chọn bài học yêu thích và bắt đầu phiêu lưu nào!'
            : isHigh
              ? 'Chọn bài học để bắt đầu ôn tập và rèn luyện.'
              : 'Chọn bài học để bắt đầu hành trình chinh phục toán học!'}
        </p>
      </div>

      {error && (
        <div className={`${theme.cardRadius} border border-red-200 bg-red-50 p-4 text-red-700`}>
          {error}
        </div>
      )}

      {nextLesson && (
        <Link href={`/dashboard/lessons/${nextLesson.lesson_id}`} className={`${theme.cardRadius} border border-blue-100 bg-blue-50 p-4 text-blue-800 flex items-start gap-3 hover:bg-blue-100 transition`}>
          <Sparkles className="w-5 h-5 mt-1" />
          <div>
            <div className="font-bold">Gợi ý học hôm nay</div>
            <div>{nextLesson.title}</div>
            {recommendation?.learning_tips?.[0] && <div className="text-sm text-blue-600 mt-1">{recommendation.learning_tips[0]}</div>}
          </div>
        </Link>
      )}

      {!nextLesson && recommendation?.learning_tips?.[0] && (
        <div className={`${theme.cardRadius} border border-amber-100 bg-amber-50 p-4 text-amber-800 flex items-start gap-3`}>
          <AlertCircle className="w-5 h-5 mt-1" />
          <div>{recommendation.learning_tips[0]}</div>
        </div>
      )}

      {activeCurriculum && (
        <div className={`${theme.cardRadius} bg-white border border-gray-100 p-4`}>
          <div className="text-sm text-gray-500">Giáo trình đang học</div>
          <div className="font-bold text-gray-900">{activeCurriculum.title}</div>
          {activeCurriculum.ai_summary && <div className="text-gray-600 mt-1 line-clamp-2">{activeCurriculum.ai_summary}</div>}
        </div>
      )}

      <div className="flex gap-2 overflow-x-auto pb-1">
        {subjects.map((s) => (
          <button
            key={s}
            onClick={() => setFilter(s)}
            className={`shrink-0 px-4 py-2 ${theme.fontWeight} transition-all ${theme.buttonRadius} text-lg ${
              filter === s
                ? 'bg-blue-600 text-white shadow-md'
                : 'bg-white text-gray-500 hover:bg-gray-100 ring-1 ring-gray-200/80'
            }`}
          >
            {s}
          </button>
        ))}
      </div>

      {loading && (
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {[0, 1, 2, 3, 4, 5].map(item => <div key={item} className={`${theme.cardRadius} h-56 bg-gray-100 animate-pulse`} />)}
        </div>
      )}

      {!loading && filtered.length === 0 && (
        <div className={`${theme.cardRadius} border border-dashed border-gray-200 bg-gray-50 p-8 text-center text-gray-600`}>
          <div className="font-bold text-gray-800 mb-1">Chưa có bài học thật</div>
          <div>Hãy hoàn thành assessment và tạo giáo trình để hệ thống sinh danh sách bài học cá nhân hóa.</div>
          <div className="mt-4 flex justify-center gap-3">
            <Link href="/dashboard/assessment" className={`${theme.buttonRadius} bg-blue-600 px-4 py-2 font-semibold text-white`}>Làm assessment</Link>
            <Link href="/dashboard/curriculum" className={`${theme.buttonRadius} bg-white px-4 py-2 font-semibold text-blue-600 ring-1 ring-blue-200`}>Xem giáo trình</Link>
          </div>
        </div>
      )}

      {!loading && filtered.length > 0 && (
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {filtered.map((lesson, i) => {
            const diff = difficultyConfig[lesson.difficulty];
            const isComplete = lesson.progress === 100;
            const isNew = lesson.progress === 0;
            return (
              <Link
                key={lesson.id}
                href={`/dashboard/lessons/${lesson.id}`}
                className={`group relative overflow-hidden shadow-sm transition-all duration-500 ${theme.cardRadius} ${theme.cardBg} ${theme.cardBorder} ${
                  isElementary
                    ? 'ring-2 ring-blue-200 hover:shadow-md hover:ring-blue-400'
                    : isHigh
                      ? 'ring-1 ring-gray-200 hover:shadow-md hover:ring-gray-300'
                      : 'ring-1 ring-gray-100/80 hover:shadow-md hover:ring-blue-200'
                } ${mounted ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}
                style={{ transitionDelay: `${i * 80}ms` }}
              >
                <div className={lesson.color} style={{ height: isElementary ? '6px' : isHigh ? '3px' : '6px' }} />

                {lesson.recommendationLabel && (
                  <div className={`absolute top-4 left-4 bg-amber-500 text-white font-bold px-2 py-0.5 rounded-full ${isElementary ? 'text-base' : 'text-sm'}`}>
                    {lesson.recommendationLabel}
                  </div>
                )}
                {isComplete && (
                  <div className={`absolute top-4 right-4 bg-emerald-500 text-white font-bold px-2 py-0.5 rounded-full ${isElementary ? 'text-base' : 'text-sm'}`}>
                    {isElementary ? 'Hoàn thành' : '✓ Hoàn thành'}
                  </div>
                )}
                {isNew && !lesson.recommendationLabel && (
                  <div className={`absolute top-4 right-4 bg-blue-500 text-white font-bold px-2 py-0.5 rounded-full ${isElementary ? 'text-base animate-bounce' : 'text-sm animate-pulse'}`}>
                    {lesson.status === 'available' ? (isElementary ? 'Sẵn sàng!' : 'Sẵn sàng') : (isElementary ? 'MỚI!' : 'MỚI')}
                  </div>
                )}

                <div className={theme.cardPadding}>
                  <div className="flex items-start gap-3 mb-3">
                    <div
                      className={`${lesson.color} text-white flex items-center justify-center shadow-sm transition-all ${
                        isElementary
                          ? 'group-hover:opacity-80'
                          : isHigh
                            ? 'group-hover:opacity-90'
                            : 'group-hover:opacity-85'
                      }`}
                      style={{
                        height: isElementary ? '3.5rem' : '3rem',
                        width: isElementary ? '3.5rem' : '3rem',
                        borderRadius: isElementary ? '1rem' : '0.75rem',
                        fontSize: isElementary ? '1.75rem' : '1.5rem',
                      }}
                    >
                      {isHigh ? lesson.title.charAt(0) : <lesson.icon className="w-6 h-6" />}
                    </div>
                    <div className="flex-1">
                      <h3 className={`${theme.fontWeight} text-gray-900 text-xl transition ${isHigh ? 'group-hover:text-gray-700' : 'group-hover:text-blue-600'}`}>
                        {lesson.title}
                      </h3>
                      <p className="text-gray-400 mt-0.5 text-lg">
                        {lesson.subject} · {lesson.grade}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-2 mb-3">
                    <span className={`font-semibold px-2 py-0.5 rounded-full text-base ${diff.bg} ${diff.text}`}>
                      {isHigh ? diff.label : lesson.difficulty}
                    </span>
                    <span className="text-gray-400 text-base">
                      {isHigh ? lesson.duration : <><Clock className="w-3 h-3 inline mr-0.5" /> {lesson.duration}</>}
                    </span>
