                  <div>
                    <div className={`flex items-center justify-between mb-1 text-lg`}>
                      <span className="text-gray-400">Tiến độ theo trạng thái API</span>
                      <span className={`font-bold ${isComplete ? 'text-emerald-600' : 'text-blue-600'}`}>{lesson.progress}%</span>
                    </div>
                    <div className={`w-full bg-gray-100 overflow-hidden ${theme.progressHeight} ${theme.progressRadius}`}>
                      <div className={`h-full transition-all duration-1000 ease-out ${theme.progressRadius} ${isComplete ? 'bg-emerald-500' : lesson.color}`} style={{ width: mounted ? `${lesson.progress}%` : '0%' }} />
                    </div>
                  </div>

                  <div className="mt-4 text-center">
                    <span className={`inline-block font-bold px-4 py-1.5 text-lg transition-all ${theme.buttonRadius} ${
                      isComplete
                        ? 'bg-emerald-50 text-emerald-600 group-hover:bg-emerald-100'
                        : isNew
                          ? 'bg-blue-500 text-white shadow-md'
                          : 'bg-blue-50 text-blue-600 group-hover:bg-blue-100'
                    }`}>
                      {isComplete ? 'Ôn tập lại' : isNew ? 'Bắt đầu' : 'Tiếp tục học'}
                    </span>
                  </div>
                </div>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

