'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { useAgeTheme } from '@/contexts/AgeThemeContext';
import { getDashboardStats, getTodayRecommendation, getTopicMastery, listLessons, type AdaptiveRecommendation, type DashboardStats, type LessonSummary, type TopicMastery } from '@/lib/api';
import { BookOpen, CheckCircle, Star, Flame, Calculator, Bot, Target, Trophy, Medal, Rocket, Triangle, Ruler, TrendingUp, Circle, Zap, Brain } from 'lucide-react';

const defaultStats: DashboardStats = {
  total_lessons: 0,
  completed_lessons: 0,
  completion_percentage: 0,
  average_quiz_score: null,
  total_study_time_minutes: 0,
  current_streak_days: 0,
  longest_streak_days: 0,
};

const lessonIcons = [Triangle, Ruler, TrendingUp, Circle];
const lessonColors = ['bg-blue-500', 'bg-emerald-500', 'bg-purple-500', 'bg-red-500'];

function lessonProgress(status?: string): number {
  if (status === 'completed') return 100;
  if (status === 'in_progress') return 50;
  return 0;
}

function lessonSubject(lesson: LessonSummary): string {
  return lesson.lesson_objective || 'Bài học cá nhân';
}

const quickActions = [
  { href: '/dashboard/solver', icon: Calculator, label: 'Giải toán AI', desc: 'Nhập bài toán, nhận lời giải', solid: 'bg-indigo-500' },
  { href: '/dashboard/chat', icon: Bot, label: 'Trợ lý AI', desc: 'Hỏi đáp 24/7', solid: 'bg-emerald-500' },
  { href: '/dashboard/assessment', icon: Target, label: 'Đánh giá', desc: 'Kiểm tra trình độ', solid: 'bg-amber-500' },
];

export default function DashboardPage() {
  const { theme, ageGroup } = useAgeTheme();
  const [mounted, setMounted] = useState(false);
  const [dashboardData, setDashboardData] = useState<DashboardStats>(defaultStats);
  const [mastery, setMastery] = useState<TopicMastery[]>([]);
  const [recommendation, setRecommendation] = useState<AdaptiveRecommendation | null>(null);
  const [recentLessons, setRecentLessons] = useState<LessonSummary[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => setMounted(true), []);

  useEffect(() => {
    let cancelled = false;
    async function fetchStats() {
      try {
        setError(null);
        const [statsData, masteryData, recommendationData, lessonsData] = await Promise.all([
          getDashboardStats(),
          getTopicMastery(),
          getTodayRecommendation(),
          listLessons(),
        ]);
        if (!cancelled) {
          setDashboardData(statsData);
          setMastery(masteryData);
          setRecommendation(recommendationData);
          setRecentLessons(lessonsData.slice(0, 4));
        }
      } catch (err) {
        if (!cancelled) setError(err instanceof Error ? err.message : 'Không tải được dữ liệu dashboard');
      } finally {
        if (!cancelled) setLoading(false);
      }
    }
    fetchStats();
    return () => { cancelled = true; };
  }, []);

  const averageMastery = mastery.length > 0
    ? Math.round(mastery.reduce((sum, item) => sum + Number(item.mastery_level || 0), 0) / mastery.length)
    : null;
  const nextLessonTitle = recommendation?.new_lesson?.title || null;
  const achievements = [
    { icon: Trophy, label: 'Điểm thưởng', value: dashboardData.points?.reward_points ?? 0, unlocked: Boolean(dashboardData.points?.reward_points) },
    { icon: Target, label: 'Mastery TB', value: averageMastery === null ? '—' : `${averageMastery}%`, unlocked: averageMastery !== null },
    { icon: Zap, label: 'Hoàn thành', value: `${dashboardData.completed_lessons}/${dashboardData.total_lessons}`, unlocked: dashboardData.completed_lessons > 0 },
    { icon: Brain, label: 'Streak', value: `${dashboardData.current_streak_days} ngày`, unlocked: dashboardData.current_streak_days > 0 },
  ];

  const stats = [
    { label: 'Tổng bài học', value: dashboardData.total_lessons, icon: BookOpen, change: dashboardData.total_lessons > 0 ? `${dashboardData.completion_percentage}%` : 'Chưa có', solid: 'bg-blue-500', border: 'border-blue-500', bg: 'bg-blue-50', color: 'text-blue-600' },
    { label: 'Bài hoàn thành', value: dashboardData.completed_lessons, icon: CheckCircle, change: `${dashboardData.completion_percentage}%`, solid: 'bg-emerald-500', border: 'border-emerald-500', bg: 'bg-emerald-50', color: 'text-emerald-600' },
    { label: 'Điểm TB', value: dashboardData.average_quiz_score === null ? '—' : Math.round(dashboardData.average_quiz_score), icon: Star, change: dashboardData.points ? `${dashboardData.points.academic_percentage}%` : 'Chưa chấm', solid: 'bg-amber-500', border: 'border-amber-500', bg: 'bg-amber-50', color: 'text-amber-600' },
    { label: 'Streak', value: `${dashboardData.current_streak_days} ngày`, icon: Flame, change: dashboardData.current_streak_days > 0 ? 'Tiếp tục!' : 'Bắt đầu', solid: 'bg-rose-500', border: 'border-rose-500', bg: 'bg-rose-50', color: 'text-rose-600' },
  ];

  const isElementary = ageGroup === 'elementary';
  const isHigh = ageGroup === 'high';

  return (
    <div className={theme.sectionGap}>
      {/* Hero Banner */}
      <div className={`relative overflow-hidden ${theme.cardRadius} bg-blue-600 ${isElementary ? 'p-8' : 'p-6'} text-white transition-all duration-700 ${mounted ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
        {theme.showAnimations && (
          <>
            <div className="absolute -top-10 -right-10 w-40 h-40 bg-white/10 rounded-full" />
            <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-white/10 rounded-full" />
          </>
        )}
        {isElementary && (
          <div className="absolute top-2 right-4 opacity-20 animate-bounce" style={{ animationDuration: '3s' }}><Rocket className="w-16 h-16" /></div>
        )}
        <div className="relative">
          <h1 className={`${theme.headingSize} ${theme.fontWeight}`}>
            {isElementary ? 'Chào mừng trở lại!' : 'Chào mừng trở lại!'}
          </h1>
          <p className={`${isElementary ? 'text-lg text-white/90' : 'text-base text-white/80'} mt-1`}>
            {isElementary
              ? `Hôm nay là ngày thứ ${dashboardData.current_streak_days} trong chuỗi streak! Giỏi lắm!`
              : `Hôm nay là ngày thứ ${dashboardData.current_streak_days} trong chuỗi streak. Tiếp tục nào!`}
          </p>
          <div className={`flex gap-3 ${isElementary ? 'mt-5' : 'mt-4'}`}>
            <Link href="/dashboard/lessons" className={`${theme.buttonRadius} bg-white/20 ${theme.buttonStyle} text-white hover:bg-white/30`}>
              {'Tiếp tục học →'}
            </Link>
            <Link href="/dashboard/solver" className={`${theme.buttonRadius} bg-white ${theme.buttonStyle} ${isElementary ? 'text-blue-600' : isHigh ? 'text-slate-700' : 'text-blue-700'} hover:bg-white/90`}>
              {'Giải toán AI'}
            </Link>
          </div>
        </div>
      </div>

      {error && (
        <div className={`${theme.cardRadius} border border-red-200 bg-red-50 p-4 text-red-700`}>
          {error}
        </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        {stats.map((stat, i) => (
          <div
            key={stat.label}
            className={`${theme.cardRadius} bg-white border-l-4 ${stat.border} ${theme.statCardStyle} ${theme.cardBorder} ${mounted ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}
            style={{ transitionDelay: `${i * 100}ms` }}
          >
            <div className="flex items-center justify-between mb-2">
              <stat.icon className={`${isElementary ? 'w-7 h-7' : 'w-5 h-5'} ${stat.color}`} />
              <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${stat.solid} text-white`}>
                {stat.change}
              </span>
            </div>
            <div className={`${isElementary ? 'text-4xl' : 'text-3xl'} font-extrabold text-gray-900`}>
              {loading ? <span className="inline-block w-12 h-8 bg-gray-200 rounded animate-pulse" /> : stat.value}
            </div>
            <div className={`${isElementary ? 'text-base' : 'text-lg'} text-gray-500 mt-0.5`}>{stat.label}</div>
          </div>
        ))}
      </div>

      {/* Recent Lessons + Achievements */}
      <div className="grid lg:grid-cols-3 gap-4">
        <div className={`lg:col-span-2 ${theme.cardRadius} ${theme.cardBg} shadow-sm ring-1 ring-gray-100/80`}>
          <div className="flex items-center justify-between p-4 border-b border-gray-100/80">
            <h2 className={`${isElementary ? 'text-xl' : 'text-lg'} ${theme.fontWeight} text-gray-900`}>
              <span className="flex items-center gap-1">{theme.showEmojis && <BookOpen className="w-5 h-5 inline" />} Bài học gần đây</span>
            </h2>
            <Link href="/dashboard/lessons" className="text-base font-semibold text-blue-600 hover:opacity-80">{'Xem tất cả →'}</Link>
          </div>
          <div className="divide-y divide-gray-50">
            {loading && [0, 1, 2].map((item) => (
              <div key={item} className={`${isElementary ? 'p-5' : 'p-4'} animate-pulse`}>
                <div className="h-12 bg-gray-100 rounded" />
              </div>
            ))}
            {!loading && recentLessons.length === 0 && (
              <div className={`${isElementary ? 'p-5' : 'p-4'} text-gray-500`}>
                Chưa có bài học thật. Hãy hoàn thành đánh giá đầu vào và tạo giáo trình để bắt đầu.
              </div>
            )}
            {!loading && recentLessons.map((lesson, i) => {
              const progress = lessonProgress(lesson.status);
              const Icon = lessonIcons[i % lessonIcons.length];
              const solid = lessonColors[i % lessonColors.length];
              return (
              <div
                key={lesson._id || lesson.id || lesson.lesson_title}
