                  <Icon className={`${isElementary ? 'w-7 h-7' : 'w-5 h-5'}`} />
                </div>
                <div className="flex-1 min-w-0">
                  <div className={`font-semibold ${isElementary ? 'text-lg' : 'text-base'} text-gray-900 group-hover:text-blue-700 transition`}>{lesson.lesson_title}</div>
                  <div className={`${isElementary ? 'text-base' : 'text-lg'} text-gray-400`}>{lessonSubject(lesson)}</div>
                </div>
                <div className="flex items-center gap-2">
                  <div className={`${isElementary ? 'w-24' : 'w-20'} ${theme.progressHeight} rounded-full bg-gray-100 overflow-hidden`}>
                    <div
                      className={`h-full rounded-full transition-all duration-1000 ${progress === 100 ? 'bg-emerald-500' : solid}`}
                      style={{ width: mounted ? `${progress}%` : '0%' }}
                    />
                  </div>
                  <span className={`text-base font-bold ${progress === 100 ? 'text-emerald-600' : 'text-gray-500'}`}>
                    {progress === 100 ? '✓' : `${progress}%`}
                  </span>
                </div>
              </div>
            );})}
          </div>
        </div>

        <div className={`${theme.cardRadius} ${theme.cardBg} shadow-sm ring-1 ring-gray-100/80 ${theme.cardPadding}`}>
          <h2 className={`${isElementary ? 'text-xl' : 'text-lg'} ${theme.fontWeight} text-gray-900 mb-3`}>
            <span className="flex items-center gap-1">{theme.showEmojis && <Medal className="w-5 h-5 inline" />} Thành tích</span>
          </h2>
          <div className="grid grid-cols-2 gap-2">
            {achievements.map((a) => (
              <div
                key={a.label}
                className={`flex flex-col items-center justify-center ${isElementary ? 'p-4' : 'p-3'} ${theme.cardRadius} border transition-all ${
                  a.unlocked
                    ? 'bg-blue-100 border-blue-200/60 hover:opacity-80'
                    : 'bg-gray-50 border-gray-100 opacity-40 grayscale'
                }`}
              >
                <a.icon className={`${isElementary ? 'w-10 h-10' : 'w-8 h-8'} mb-1 ${a.unlocked ? 'text-blue-700' : 'text-gray-600'}`} />
                <span className={`${isElementary ? 'text-base' : 'text-xs'} font-semibold text-center ${a.unlocked ? 'text-blue-700' : 'text-gray-600'}`}>{a.label}</span>
                <span className={`text-xs font-bold ${a.unlocked ? 'text-blue-800' : 'text-gray-500'}`}>{a.value}</span>
              </div>
            ))}
          </div>
          <Link href="/dashboard/progress" className={`block mt-3 text-center text-base font-semibold text-blue-600 hover:opacity-80`}>
            {'Xem tất cả thành tích →'}
          </Link>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid sm:grid-cols-3 gap-3">
        {quickActions.map((action, i) => (
          <Link
            key={action.href}
            href={action.href}
            className={`group ${theme.cardRadius} ${action.solid} ${isElementary ? 'p-7' : 'p-5'} text-white shadow-md transition-all hover:opacity-90 duration-500 ${mounted ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}
            style={{ transitionDelay: `${i * 100 + 400}ms` }}
          >
            <action.icon className={`${isElementary ? 'w-12 h-12' : 'w-8 h-8'} mb-2`} />
            <div className={`${theme.fontWeight} ${isElementary ? 'text-2xl' : 'text-lg'}`}>{action.label}</div>
            <div className={`text-white/80 ${isElementary ? 'text-base' : 'text-lg'} mt-0.5`}>{action.desc}</div>
          </Link>
        ))}
      </div>

      {nextLessonTitle && (
        <div className={`${theme.cardRadius} bg-blue-50 border border-blue-100 p-4 text-blue-800`}>
          Gợi ý hôm nay: <span className="font-bold">{nextLessonTitle}</span>
        </div>
      )}

      {/* Mascot section for elementary */}
      {isElementary && (
        <div className={`${theme.cardRadius} bg-cyan-50 border-2 border-cyan-200/60 p-6 flex items-center gap-4`}>
          <Rocket className="w-12 h-12 text-cyan-600 animate-bounce" style={{ animationDuration: '2s' }} />
          <div>
            <p className="text-xl font-bold text-cyan-800">{'Bạn đang làm rất tốt!'}</p>
            <p className="text-base text-cyan-600 mt-1">{nextLessonTitle ? `Bài gợi ý hôm nay: ${nextLessonTitle}` : 'Tạo giáo trình để nhận gợi ý học cá nhân hóa nhé!'}</p>
          </div>
        </div>
      )}
    </div>
  );
}

