"use client";

import { useEffect, useMemo, useState } from "react";
import {
	getParentNotifications,
	markAllParentNotificationsRead,
	markParentNotificationRead,
	type ParentNotification,
} from "@/lib/api";

function iconForNotification(notification: ParentNotification): string {
	if (notification.severity === "critical") return "🚨";
	if (notification.severity === "warning") return "⚠️";
	if (notification.type === "session_complete") return "✅";
	if (notification.type === "session_start") return "📚";
	if (notification.type === "achievement") return "🏆";
	return "🔔";
}

function formatTime(value?: string | null): string {
	if (!value) return "Không rõ thời gian";
	const date = new Date(value);
	if (Number.isNaN(date.getTime())) return value;
	return date.toLocaleString("vi-VN");
}

export default function NotificationsPage() {
	const [notifications, setNotifications] = useState<ParentNotification[]>([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState<string | null>(null);
	const [actionError, setActionError] = useState<string | null>(null);
	const [updatingId, setUpdatingId] = useState<string | null>(null);

	async function loadNotifications() {
		try {
			setLoading(true);
			setError(null);
			setNotifications(await getParentNotifications(50));
		} catch (loadError) {
			setError(loadError instanceof Error ? loadError.message : "Không tải được thông báo");
			setNotifications([]);
		} finally {
			setLoading(false);
		}
	}

	useEffect(() => {
		loadNotifications();
	}, []);

	const unreadCount = useMemo(() => notifications.filter((item) => !item.is_read).length, [notifications]);

	async function handleMarkRead(notification: ParentNotification) {
		const id = notification.id ?? notification._id;
		if (!id || notification.is_read) return;
		try {
			setActionError(null);
			setUpdatingId(id);
			await markParentNotificationRead(id);
			setNotifications((current) => current.map((item) => ((item.id ?? item._id) === id ? { ...item, is_read: true, read_at: new Date().toISOString() } : item)));
		} catch (markError) {
			setActionError(markError instanceof Error ? markError.message : "Không đánh dấu đã đọc được");
		} finally {
			setUpdatingId(null);
		}
	}

	async function handleMarkAllRead() {
		try {
			setActionError(null);
			setUpdatingId("all");
			await markAllParentNotificationsRead();
			const now = new Date().toISOString();
			setNotifications((current) => current.map((item) => ({ ...item, is_read: true, read_at: item.read_at ?? now })));
		} catch (markError) {
			setActionError(markError instanceof Error ? markError.message : "Không đánh dấu tất cả đã đọc được");
		} finally {
			setUpdatingId(null);
		}
	}

	if (loading) {
		return (
			<div className="rounded-2xl bg-white p-8 text-center shadow-sm ring-1 ring-gray-100">
				<div className="mx-auto mb-3 h-8 w-8 animate-spin rounded-full border-4 border-indigo-600 border-t-transparent" />
				<p className="text-sm text-gray-500">Đang tải thông báo...</p>
			</div>
		);
	}

	return (
		<div className="space-y-6">
			<div className="flex items-start justify-between gap-4">
				<div>
					<h1 className="text-2xl font-bold text-gray-900">Thông báo 🔔</h1>
					<p className="text-gray-500">Thông báo in-app từ API phụ huynh. Chưa triển khai email/SMS/push production job.</p>
				</div>
				<button
					type="button"
					onClick={handleMarkAllRead}
					disabled={unreadCount === 0 || updatingId === "all"}
					className="rounded-xl bg-indigo-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-indigo-700 disabled:cursor-not-allowed disabled:bg-gray-300"
				>
					Đánh dấu tất cả đã đọc ({unreadCount})
				</button>
			</div>

			{error && <div className="rounded-2xl border border-red-100 bg-red-50 p-5 text-sm text-red-700">{error}</div>}
			{actionError && <div className="rounded-2xl border border-amber-100 bg-amber-50 p-4 text-sm text-amber-700">{actionError}</div>}

			{!error && notifications.length === 0 && (
				<div className="rounded-2xl bg-white p-8 text-center shadow-sm ring-1 ring-gray-100">
					<div className="text-4xl">📭</div>
					<h2 className="mt-3 text-lg font-bold text-gray-900">Chưa có thông báo</h2>
					<p className="mt-2 text-sm text-gray-500">Thông báo sẽ xuất hiện khi học sinh bắt đầu/hoàn thành buổi học, có cảnh báo rủi ro hoặc backend tạo notification thật.</p>
				</div>
			)}

			{notifications.length > 0 && (
				<div className="rounded-2xl bg-white shadow-sm ring-1 ring-gray-100">
					<div className="divide-y divide-gray-50">
						{notifications.map((notification) => {
							const id = notification.id ?? notification._id ?? `${notification.title}-${notification.created_at}`;
							return (
								<div key={id} className={`flex items-start gap-4 p-5 ${!notification.is_read ? "bg-indigo-50/50" : ""}`}>
									<span className="text-2xl">{iconForNotification(notification)}</span>
									<div className="flex-1">
										<div className={`font-medium ${!notification.is_read ? "text-gray-900" : "text-gray-600"}`}>{notification.title}</div>
										{notification.content && <div className="mt-1 whitespace-pre-line text-sm text-gray-500">{notification.content}</div>}
										<div className="mt-2 text-xs text-gray-400">{formatTime(notification.created_at ?? notification.createdAt)}</div>
									</div>
									{!notification.is_read ? (
										<button
											type="button"
											onClick={() => handleMarkRead(notification)}
											disabled={updatingId === id}
											className="rounded-lg border border-indigo-200 px-3 py-1 text-xs font-medium text-indigo-600 hover:bg-indigo-50 disabled:cursor-not-allowed disabled:opacity-50"
										>
											Đã đọc
										</button>
									) : (
										<span className="rounded-full bg-gray-100 px-3 py-1 text-xs text-gray-500">Đã đọc</span>
									)}
								</div>
							);
						})}
					</div>
				</div>
			)}
		</div>
	);
}

