﻿"use client";

import { ArrowLeft, Loader2, Save } from "lucide-react";
import Link from "next/link";
import { type FormEvent, useEffect, useState } from "react";
import {
	type ContentAssignment,
	type ContentAssignmentStatus,
	contentLibraryApi,
} from "@/lib/content-library";

const statusOptions: Array<{ value: ContentAssignmentStatus; label: string }> =
	[
		{ value: "active", label: "Đang hoạt động" },
		{ value: "paused", label: "Tạm dừng" },
		{ value: "archived", label: "Lưu trữ" },
	];

function titleOf(assignment: ContentAssignment): string {
	return (
		assignment.template_snapshot?.title ||
		assignment.template_snapshot?.lesson_title ||
		assignment.template_id
	);
}

export default function AssignmentEdit({
	id,
	basePath,
}: {
	id: string;
	basePath: "/admin/assignments" | "/teacher/content-library/assignments";
}) {
	const [assignment, setAssignment] = useState<ContentAssignment | null>(null);
	const [status, setStatus] = useState<ContentAssignmentStatus>("active");
	const [autoApply, setAutoApply] = useState(false);
	const [loading, setLoading] = useState(true);
	const [saving, setSaving] = useState(false);
	const [error, setError] = useState("");
	const [notice, setNotice] = useState("");
	const isArchivedAssignment = assignment?.status === "archived";

	useEffect(() => {
		let active = true;
		setLoading(true);
		setError("");
		contentLibraryApi
			.getAssignmentDetail(id)
			.then((res) => {
				if (!active) return;
				setAssignment(res.data);
				setStatus(res.data.status);
				setAutoApply(Boolean(res.data.auto_apply_new_students));
			})
			.catch((err) => {
				if (active)
					setError(
						err instanceof Error ? err.message : "Không thể tải assignment",
					);
			})
			.finally(() => {
				if (active) setLoading(false);
			});
		return () => {
			active = false;
		};
	}, [id]);

	async function onSubmit(event: FormEvent<HTMLFormElement>) {
		event.preventDefault();
		if (!assignment) return;
		setSaving(true);
		setError("");
		setNotice("");
		try {
			if (assignment?.status === "archived" && status === "active") {
				setError(
					"Archived assignments cannot be reactivated from this screen because archived deliveries are not restored.",
				);
				return;
			}

			let updatedAssignment = assignment;
			if (assignment.auto_apply_new_students !== autoApply) {
				const res = await contentLibraryApi.updateAssignment(id, {
					auto_apply_new_students: autoApply,
				});
				updatedAssignment = res.data;
			}
			if (assignment?.status !== status) {
				if (status === "active") {
					const res = await contentLibraryApi.activateAssignment(id);
					updatedAssignment = res.data;
				}
				if (status === "paused") {
					const res = await contentLibraryApi.pauseAssignment(id);
					updatedAssignment = res.data;
				}
				if (status === "archived") {
					const res = await contentLibraryApi.archiveAssignment(id);
					updatedAssignment = res.data;
				}
			}
			setAssignment(updatedAssignment);
			setStatus(updatedAssignment.status);
			setAutoApply(Boolean(updatedAssignment.auto_apply_new_students));
			setNotice("Đã lưu thay đổi assignment.");
		} catch (err) {
			setError(err instanceof Error ? err.message : "Không thể lưu assignment");
		} finally {
			setSaving(false);
		}
	}

	if (loading) {
		return (
			<div
				data-testid="assignment-edit-loading"
				className="flex justify-center py-20"
			>
				<Loader2 className="h-8 w-8 animate-spin text-blue-600" />
			</div>
		);
	}
	if (error && !assignment) {
		return (
			<div
				role="alert"
				data-testid="assignment-edit-error"
				className="rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700"
			>
				{error}
			</div>
		);
	}
	if (!assignment) {
		return (
			<div
				data-testid="assignment-edit-empty"
				className="rounded-xl border border-dashed border-gray-200 p-8 text-center text-sm text-gray-500"
			>
				Không tìm thấy assignment để chỉnh sửa.
			</div>
		);
	}

	return (
		<div data-testid="assignment-edit" className="mx-auto max-w-3xl space-y-6">
			<nav aria-label="Điều hướng chỉnh sửa assignment">
				<Link
					href={`${basePath}/${id}`}
					className="inline-flex items-center gap-2 text-sm font-medium text-gray-500 hover:text-gray-900"
				>
					<ArrowLeft className="h-4 w-4" /> Quay lại chi tiết assignment
				</Link>
			</nav>
			<header>
				<h1 className="text-2xl font-bold text-gray-900">
					Chỉnh sửa assignment
				</h1>
				<p className="mt-1 text-sm text-gray-500">
					Điều chỉnh trạng thái phân phối cho “{titleOf(assignment)}”.
				</p>
			</header>

			{error && (
				<div
					role="alert"
					className="rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700"
				>
					{error}
				</div>
			)}
			{notice && (
				<div
					role="status"
					className="rounded-xl border border-blue-200 bg-blue-50 p-4 text-sm text-blue-800"
				>
					{notice}
				</div>
			)}

			<form
				onSubmit={onSubmit}
				className="space-y-5 rounded-2xl border border-gray-200 bg-white p-6 shadow-sm"
			>
				<div>
					<label
						htmlFor="assignment-title"
						className="text-sm font-semibold text-gray-700"
					>
						Nội dung được gán
					</label>
					<div id="assignment-title-display" className="mt-1 w-full rounded-lg border border-gray-200 bg-gray-50 px-3 py-2 text-sm text-gray-600">{titleOf(assignment)}</div>
				</div>
				<div>
					<label
						htmlFor="assignment-status"
						className="text-sm font-semibold text-gray-700"
					>
						Trạng thái
					</label>
					<select
						id="assignment-status"
						value={status}
						onChange={(e) =>
							setStatus(e.target.value as ContentAssignmentStatus)
						}
						className="mt-1 w-full rounded-lg border border-gray-200 px-3 py-2 text-sm outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-100"
					>
						{statusOptions.map((option) => (
							<option
								key={option.value}
								value={option.value}
								disabled={isArchivedAssignment && option.value === "active"}
							>
								{option.label}
							</option>
						))}
					</select>
					{isArchivedAssignment && (
						<p className="mt-2 text-xs text-gray-500">
							Archived assignments cannot be reactivated from this screen
							because archived deliveries are not restored. Tạo assignment mới
							nếu cần phân phối lại nội dung.
						</p>
					)}
				</div>
				<div className="rounded-xl border border-gray-200 p-4">
					<label
						htmlFor="assignment-auto-apply"
						className="flex items-start gap-3 text-sm font-semibold text-gray-700"
					>
						<input
							id="assignment-auto-apply"
							type="checkbox"
							checked={autoApply}
							onChange={(e) => setAutoApply(e.target.checked)}
							className="mt-1"
						/>
						<span>
							<span className="block">Tự áp dụng cho học sinh mới</span>
							<span className="mt-1 block font-normal text-gray-500">
								Khi bật, học sinh mới được thêm vào lớp sẽ nhận nội dung này tự
								động.
							</span>
						</span>
					</label>
				</div>
				<div className="flex flex-col-reverse gap-3 border-t border-gray-100 pt-5 sm:flex-row sm:justify-end">
					<Link
						href={`${basePath}/${id}`}
						className="inline-flex justify-center rounded-lg bg-gray-100 px-4 py-2 text-sm font-semibold text-gray-700 hover:bg-gray-200"
					>
						Hủy
					</Link>
					<button
						type="submit"
						disabled={saving}
						className="inline-flex justify-center gap-2 rounded-lg bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:cursor-not-allowed disabled:opacity-60"
					>
						<Save className="h-4 w-4" />{" "}
						{saving ? "Đang lưu..." : "Lưu thay đổi"}
					</button>
				</div>
			</form>
		</div>
	);
}

"use client";

import { Archive, Loader2, Pause, Play, RefreshCw } from "lucide-react";
import Link from "next/link";
import { useCallback, useEffect, useState } from "react";
import {
	type ContentAssignment,
	type ContentAssignmentStatus,
	contentLibraryApi,
	getAssignmentId,
	type PaginationMeta,
} from "@/lib/content-library";

const statusLabels: Record<ContentAssignmentStatus, string> = {
	active: "Đang hoạt động",
	paused: "Tạm dừng",
	archived: "Lưu trữ",
};

const statusClasses: Record<ContentAssignmentStatus, string> = {
	active: "bg-emerald-50 text-emerald-700 border-emerald-200",
	paused: "bg-amber-50 text-amber-700 border-amber-200",
	archived: "bg-gray-50 text-gray-700 border-gray-200",
};

function assignmentTitle(assignment: ContentAssignment): string {
	return (
		assignment.template_snapshot?.title ||
		assignment.template_snapshot?.lesson_title ||
		`${assignment.template_type === "curriculum_template" ? "Giáo trình" : "Bài học"} ${assignment.template_id}`
	);
}

function recipientCount(assignment: ContentAssignment): number | undefined {
	return (
		assignment.recipients_count ??
		assignment.recipient_mapping?.applied_student_ids?.length ??
		assignment.student_contents?.length
	);
}

function PaginationControls({
	meta,
	onPageChange,
}: {
	meta: PaginationMeta;
	onPageChange: (page: number) => void;
}) {
	const canPrev = meta.page > 1;
	const canNext = meta.page < meta.totalPages;
	return (
		<div className="flex flex-col gap-2 rounded-xl border border-gray-100 bg-white px-4 py-3 text-sm text-gray-600 md:flex-row md:items-center md:justify-between">
			<span>
				Trang <span className="font-semibold text-gray-900">{meta.page}</span>/
				{Math.max(meta.totalPages, 1)} · {meta.total} assignment
			</span>
			<div className="flex gap-2">
				<button
					onClick={() => onPageChange(meta.page - 1)}
					disabled={!canPrev}
					className="rounded-lg bg-gray-100 px-3 py-1.5 text-xs font-semibold text-gray-600 hover:bg-gray-200 disabled:cursor-not-allowed disabled:opacity-50"
				>
					Trước
				</button>
				<button
					onClick={() => onPageChange(meta.page + 1)}
					disabled={!canNext}
					className="rounded-lg bg-gray-100 px-3 py-1.5 text-xs font-semibold text-gray-600 hover:bg-gray-200 disabled:cursor-not-allowed disabled:opacity-50"
				>
					Sau
				</button>
			</div>
		</div>
	);
}

export default function AssignmentList({
	basePath,
	roleLabel,
}: {
	basePath:
		| "/admin/assignments"
		| "/teacher/assignments"
		| "/teacher/content-library/assignments";
	roleLabel: string;
}) {
	const [assignments, setAssignments] = useState<ContentAssignment[]>([]);
	const [meta, setMeta] = useState<PaginationMeta>({
		total: 0,
		page: 1,
		limit: 10,
		totalPages: 1,
	});
	const [status, setStatus] = useState<"all" | ContentAssignmentStatus>("all");
	const [loading, setLoading] = useState(true);
	const [processing, setProcessing] = useState<string | null>(null);
	const [error, setError] = useState("");

	const load = useCallback(
		async (page = meta.page) => {
			setLoading(true);
			setError("");
			try {
				const res = await contentLibraryApi.listAssignments({
					page,
					limit: meta.limit,
					status: status === "all" ? undefined : status,
				});
				setAssignments(res.data);
				setMeta(res.meta);
			} catch (err) {
				setError(
					err instanceof Error
						? err.message
						: "Không thể tải danh sách assignment",
				);
			} finally {
				setLoading(false);
			}
		},
		[meta.limit, meta.page, status],
	);

	useEffect(() => {
		load(1);
	}, [status]);

	async function updateAssignmentStatus(
		id: string,
		action: "pause" | "activate" | "archive",
	) {
		setProcessing(id);
		setError("");
		try {
			if (action === "pause") await contentLibraryApi.pauseAssignment(id);
			if (action === "activate") await contentLibraryApi.activateAssignment(id);
			if (action === "archive") await contentLibraryApi.archiveAssignment(id);
			await load(meta.page);
		} catch (err) {
			setError(
				err instanceof Error ? err.message : "Không thể cập nhật assignment",
			);
		} finally {
			setProcessing(null);
		}
	}

	return (
		<div data-testid="assignment-list" className="space-y-6">
			<header className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
				<div>
					<p className="text-sm font-medium text-blue-600">{roleLabel}</p>
					<h1 className="text-2xl font-bold text-gray-900">
						Kiểm tra & assignments
					</h1>
					<p className="mt-1 text-sm text-gray-500">
						Dùng assignment content-library hiện có để quản lý nội dung “kiểm
						tra” khi chưa có thư viện assessment-template riêng.
					</p>
				</div>
				<button
					onClick={() => load(meta.page)}
					className="inline-flex items-center gap-2 rounded-lg bg-gray-100 px-4 py-2 text-sm font-semibold text-gray-700 hover:bg-gray-200"
				>
					<RefreshCw className="h-4 w-4" /> Tải lại
				</button>
			</header>

			<div
				role="tablist"
				aria-label="Lọc trạng thái assignment"
				className="flex flex-wrap gap-2 border-b border-gray-200 pb-3"
			>
				{(["all", "active", "paused", "archived"] as const).map((item) => (
					<button
						key={item}
						role="tab"
						aria-selected={status === item}
						onClick={() => setStatus(item)}
						className={`rounded-lg px-3 py-1.5 text-sm font-semibold ${status === item ? "bg-blue-600 text-white" : "bg-gray-100 text-gray-600 hover:bg-gray-200"}`}
					>
						{item === "all" ? "Tất cả" : statusLabels[item]}
					</button>
				))}
			</div>

			{error && (
				<div
					role="alert"
					className="rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700"
				>
					{error}
				</div>
			)}

			{loading ? (
				<div className="flex justify-center py-20">
					<Loader2 className="h-8 w-8 animate-spin text-blue-600" />
				</div>
			) : assignments.length === 0 ? (
				<div className="rounded-xl border border-dashed border-gray-200 bg-white p-10 text-center text-sm text-gray-500">
					Chưa có assignment/kiểm tra phù hợp bộ lọc.
				</div>
			) : (
				<section className="space-y-3" aria-label="Danh sách assignments">
					{assignments.map((assignment) => {
						const id = getAssignmentId(assignment);
						const count = recipientCount(assignment);
						return (
							<article
								key={id}
								className="rounded-xl border border-gray-200 bg-white p-5 shadow-sm"
							>
								<div className="flex flex-col gap-3 md:flex-row md:items-start md:justify-between">
									<Link href={`${basePath}/${id}`} className="min-w-0 flex-1">
										<div className="flex flex-wrap items-center gap-2">
											<h2 className="font-semibold text-gray-900">
												{assignmentTitle(assignment)}
											</h2>
											<span
												className={`rounded-full border px-2 py-0.5 text-xs font-medium ${statusClasses[assignment.status]}`}
											>
												{statusLabels[assignment.status]}
											</span>
										</div>
										<div className="mt-2 flex flex-wrap gap-2 text-xs text-gray-500">
											<span>
												{assignment.template_type === "curriculum_template"
													? "Giáo trình"
													: "Bài học"}
											</span>
											<span>•</span>
											<span>
												{assignment.target_type === "class"
													? "Lớp"
													: "Học sinh"}
												: {String(assignment.target_id)}
											</span>
											{typeof count === "number" && (
												<>
													<span>•</span>
													<span>{count} học sinh</span>
												</>
											)}
											<span>•</span>
											<span>
												{new Date(assignment.createdAt).toLocaleDateString(
													"vi-VN",
												)}
											</span>
										</div>
									</Link>
									<div className="flex flex-wrap gap-2">
										{assignment.status === "active" && (
											<button
												onClick={() => updateAssignmentStatus(id, "pause")}
												disabled={processing === id}
												className="inline-flex items-center gap-1 rounded-lg bg-amber-100 px-3 py-1.5 text-xs font-semibold text-amber-700 hover:bg-amber-200 disabled:opacity-50"
											>
												<Pause className="h-3.5 w-3.5" /> Tạm dừng
											</button>
										)}
										{assignment.status === "paused" && (
											<button
												onClick={() => updateAssignmentStatus(id, "activate")}
												disabled={processing === id}
												className="inline-flex items-center gap-1 rounded-lg bg-emerald-100 px-3 py-1.5 text-xs font-semibold text-emerald-700 hover:bg-emerald-200 disabled:opacity-50"
											>
												<Play className="h-3.5 w-3.5" /> Kích hoạt
											</button>
										)}
										{assignment.status !== "archived" && (
											<button
												onClick={() => updateAssignmentStatus(id, "archive")}
												disabled={processing === id}
												className="inline-flex items-center gap-1 rounded-lg bg-gray-200 px-3 py-1.5 text-xs font-semibold text-gray-700 hover:bg-gray-300 disabled:opacity-50"
											>
												<Archive className="h-3.5 w-3.5" /> Lưu trữ
											</button>
										)}
									</div>
								</div>
							</article>
						);
					})}
				</section>
			)}

			<PaginationControls meta={meta} onPageChange={load} />
		</div>
	);
}

